using namespace std;



const int N = 2010;



vector <int> adj[N];

int dist[N];

int ans[N];







int main() {

	int n, x, y;

	cin >> n >> x >> y;

	for (int i = 1; i < n; ++i) {

		adj[i].push_back(i+1);

		adj[i+1].push_back(i);

	}



	adj[x].push_back(y);

	adj[y].push_back(x);





	for (int i = 1; i <= n; ++i) {

		memset(dist, 0x3f3f3f3f, sizeof dist);

		dist[i] = 0;

		queue<int> q;

		q.push(i);



		while(!q.empty()) {

			int f = q.front();

			q.pop();

			for (int at: adj[f]) {

				if(dist[at] == 0x3f3f3f3f) {

					dist[at] = dist[f] + 1;

					q.push(at);

				}

			}

		}

		for (int j = i+1; j <= n; ++j) {

			ans[dist[j]]++;

		}

	}

	for (int i = 1; i < n; ++i) {

		cout << ans[i] << endl;

	}

}

